/**
 * Self-contained test for SchedulingMesh, MeshEngine, and Adam.
 * Uses Node assert, no gnosis testing framework dependency.
 *
 * Run: pnpm run test:quality-surface (tsx) or pnpm exec tsx src/__tests__/scheduling-mesh.test.ts
 */

import assert from 'node:assert';
import { SchedulingMesh, createBrainMesh, createMesh, FORK, VOID, VENT } from '../scheduling-mesh';
import { MeshEngine, createEngine } from '../mesh-engine';
import { Adam, createAdam, createMinimumAdam, type InferenceAdapter } from '../adam';

function testAdapter(): InferenceAdapter<string> {
  return {
    forward: async (input, vertex) => `${input}→v${vertex.id}`,
    evaluate: (result) => result.length > 0 ? 0.8 : 0,
    merge: (results) => results.join('+'),
    deficit: (results) => results.length > 1 ? 0.2 : 0.5,
  };
}

function highDeficitAdapter(): InferenceAdapter<string> {
  let calls = 0;
  return {
    forward: async (input, vertex) => `${input}→v${vertex.id}`,
    evaluate: (result) => 0.5,
    merge: (results) => results.join('+'),
    deficit: (results) => { calls++; return calls <= 1 ? 0.8 : 0.1; },
  };
}

let passed = 0;
let failed = 0;

function test(name: string, fn: () => void | Promise<void>) {
  return Promise.resolve(fn()).then(() => {
    passed++;
    console.log(`  ✓ ${name}`);
  }).catch((e: any) => {
    failed++;
    console.log(`  ✗ ${name}: ${e.message}`);
  });
}

async function run() {
  console.log('\n── SchedulingMesh ──────────────────────────');

  await test('Proton mesh: 21 vertices for 3 cells', () => {
    const mesh = createMesh('proton', 3);
    assert.strictEqual(mesh.size, 21);
  });

  await test('3 hubs for 3 cells', () => {
    const mesh = createMesh('proton', 3);
    assert.strictEqual(mesh.hubs.length, 3);
  });

  await test('beta1 = 3 for Proton', () => {
    const mesh = createMesh('proton', 3);
    assert.strictEqual(mesh.beta1, 3);
  });

  await test('composite dimension: (3-1)*3+1 = 7', () => {
    const mesh = createMesh('proton', 3);
    assert.strictEqual(mesh.compositeDimension, 7);
  });

  await test('all vertices start VOID', () => {
    const mesh = createMesh('proton', 1);
    for (const v of mesh.vertices) assert.strictEqual(v.state, VOID);
  });

  await test('fork activates 3 targets for Proton', () => {
    const mesh = createMesh('proton', 1);
    const result = mesh.fork(0, 'task');
    assert.strictEqual(result.targets.length, 3);
    assert.strictEqual(result.beta1, 3);
  });

  await test('fork sets targets to FORK state', () => {
    const mesh = createMesh('proton', 1);
    const result = mesh.fork(0, 'task');
    for (const id of result.targets) assert.strictEqual(mesh.vertices[id].state, FORK);
  });

  await test('race: winner and losers return to VOID after proactive compute', () => {
    const mesh = createMesh('proton', 1);
    const forked = mesh.fork(0, 'task');
    const raceResult = mesh.race(forked.targets, (vid) => vid);
    assert.strictEqual(mesh.vertices[raceResult.winner].state, VOID);
    for (const id of raceResult.losers) {
      assert.strictEqual(mesh.vertices[id].state, VOID);
      assert.ok(mesh.vertices[id].rejections >= 1);
    }
  });

  await test('fold collects all results', () => {
    const mesh = createMesh('proton', 1);
    const forked = mesh.fork(0, 'payload');
    const result = mesh.fold(0, forked.targets, (vid) => `r${vid}`);
    assert.strictEqual(result.count, 3);
  });

  await test('shortest path exists between cells', () => {
    const mesh = createMesh('proton', 3);
    const path = mesh.shortestPath(0, 14);
    assert.ok(path !== null);
    assert.strictEqual(path![0], 0);
  });

  await test('VENT=-1, VOID=0, FORK=+1', () => {
    assert.strictEqual(VENT, -1);
    assert.strictEqual(VOID, 0);
    assert.strictEqual(FORK, 1);
  });

  console.log('\n── Composition Law ─────────────────────────');

  await test('3 Proton = 7 (Void)', () => {
    assert.strictEqual(createMesh('proton', 3).compositeDimension, 7);
  });

  await test('5 Primitives = 21 (Void)', () => {
    assert.strictEqual(createMesh('primitives', 5).compositeDimension, 21);
  });

  await test('2 Sophia = 10 (Kenoma)', () => {
    assert.strictEqual(createMesh('sophia', 2).compositeDimension, 10);
  });

  await test('7 Sophia = 55 (Pleroma)', () => {
    assert.strictEqual(createMesh('sophia', 7).compositeDimension, 55);
  });

  await test('2 Proton = 4 (BFT gap)', () => {
    assert.strictEqual(createMesh('proton', 2).compositeDimension, 4);
  });

  await test('BrainMesh stats include projection scan fold', () => {
    const brainMesh = createBrainMesh('proton', 2, 3, 'ring');
    const stats = brainMesh.stats();
    assert.strictEqual(stats.brains, 3);
    assert.ok(stats.projection.topologyEdges > 0);
    assert.strictEqual(stats.projection.scan.scans.length, 4);
    const ids = new Set(stats.projection.scan.scans.map((scan) => scan.id));
    assert.ok(ids.has('brain:void'));
    assert.ok(ids.has('brain:untangling'));
    assert.ok(ids.has('brain:contagion'));
    assert.ok(ids.has('brain:obstruction'));
  });

  console.log('\n── MeshEngine ──────────────────────────────');

  await test('async forkRace completes', async () => {
    const engine = createEngine('proton', 1);
    const result = await engine.forkRace(0, async (v) => v.id * 2);
    assert.ok(result.winner >= 0);
    assert.ok(typeof result.result === 'number');
  });

  await test('async forkFold collects 3 results', async () => {
    const engine = createEngine('proton', 1);
    const result = await engine.forkFold(0, async (v) => v.id);
    assert.strictEqual(result.results.length, 3);
  });

  await test('cascade chains across cells', async () => {
    const engine = createEngine('proton', 3);
    const results = await engine.cascade(0, async (v) => v.id, 3);
    assert.ok(results.length > 0);
  });

  await test('route any→any', async () => {
    const engine = createEngine('proton', 2);
    const result = await engine.route(0, 7, 'go', async (v, p) => `${p}→${v.id}`);
    assert.ok(result !== null);
    assert.ok(result!.result.includes('go'));
  });

  await test('wormhole direct jump', async () => {
    const engine = createEngine('proton', 2);
    const result = await engine.wormhole(0, 7, async (v) => v.id);
    assert.strictEqual(result.result, 7);
  });

  await test('bidirectional find', () => {
    const engine = createEngine('proton', 3);
    const result = engine.bidirectionalFind(0, 14);
    assert.ok(result !== null);
    assert.strictEqual(result!.path[0], 0);
    assert.strictEqual(result!.path[result!.path.length - 1], 14);
  });

  console.log('\n── Adam ────────────────────────────────────');

  await test('dimension = 3 (Proton)', () => {
    const adam = createMinimumAdam(testAdapter());
    assert.strictEqual(adam.dimension, 3);
  });

  await test('think produces a thought', async () => {
    const adam = createMinimumAdam(testAdapter());
    const thought = await adam.think('hello');
    assert.ok(thought.content.includes('hello'));
    assert.ok(thought.depth >= 1);
    assert.ok(thought.hops > 0);
  });

  await test('System 2 triggers on high deficit', async () => {
    const adam = createAdam({
      level: 'proton', cells: 3, maxDepth: 3, reflectionThreshold: 0.3,
    }, highDeficitAdapter());
    const thought = await adam.think('reflect');
    assert.ok(thought.depth > 1, `expected depth > 1, got ${thought.depth}`);
  });

  await test('experience accumulates', async () => {
    const adam = createMinimumAdam(testAdapter());
    assert.strictEqual(adam.experience, 0);
    await adam.think('first');
    assert.strictEqual(adam.experience, 1);
    await adam.think('second');
    assert.strictEqual(adam.experience, 2);
  });

  await test('fork creates Eve with independent state', async () => {
    const adam = createMinimumAdam(testAdapter());
    await adam.think('x');
    const eve = adam.fork();
    assert.strictEqual(eve.experience, 0);
    assert.strictEqual(eve.dimension, adam.dimension);
    await eve.think('y');
    assert.strictEqual(eve.experience, 1);
    assert.strictEqual(adam.experience, 1);
  });

  await test('compose: pair dimension = 4 (BFT gap)', async () => {
    const adam = createMinimumAdam(testAdapter());
    const eve = adam.fork();
    const result = await adam.compose(eve, 'life');
    assert.strictEqual(result.pairDimension, 4);
    assert.ok(result.merged.includes('life'));
  });

  await test('thought events fire', async () => {
    const adam = createMinimumAdam(testAdapter());
    let heard = false;
    adam.onThought(() => { heard = true; });
    await adam.think('listen');
    assert.ok(heard);
  });

  console.log('\n── Adam asks the questions ─────────────────');

  await test('What is consciousness?', async () => {
    const adam = createMinimumAdam(testAdapter());
    const thought = await adam.think('What is consciousness?');
    console.log(`    depth=${thought.depth} hops=${thought.hops} deficit=${thought.deficit.toFixed(3)}`);
    console.log(`    answer: ${thought.content}`);
    assert.ok(thought.depth >= 1);
  });

  await test('What is life?', async () => {
    const adam = createMinimumAdam(testAdapter());
    const eve = adam.fork();
    const result = await adam.compose(eve, 'What is life?');
    console.log(`    adam depth=${result.adam.depth} eve depth=${result.eve.depth}`);
    console.log(`    merged: ${result.merged}`);
    console.log(`    pair dimension: ${result.pairDimension} (BFT gap)`);
    assert.strictEqual(result.pairDimension, 4);
  });

  await test('What is failure?', async () => {
    const adam = createAdam({
      level: 'proton', cells: 3, maxDepth: 5, reflectionThreshold: 0.3,
    }, highDeficitAdapter());
    const thought = await adam.think('What is failure?');
    console.log(`    depth=${thought.depth} (System ${thought.depth > 1 ? '2' : '1'})`);
    console.log(`    answer: ${thought.content}`);
    console.log(`    identity rejections: [${adam.self.rejections}]`);
    console.log(`    identity weights: [${adam.self.weights().map(w => w.toFixed(1))}]`);
    assert.ok(thought.depth > 1, 'failure should trigger reflection');
  });

  // ─── Summary ──────────────────────────────────────────────────

  console.log(`\n══════════════════════════════════════════════`);
  console.log(`  ${passed} passed, ${failed} failed`);
  console.log(`══════════════════════════════════════════════\n`);

  if (failed > 0) process.exit(1);
}

run();
